import{_ as e,o as s,c as a,a6 as t}from"./chunks/framework.BBdhcoHf.js";const k=JSON.parse('{"title":"Server","description":"","frontmatter":{},"headers":[],"relativePath":"guide/server.md","filePath":"guide/server.md"}'),n={name:"guide/server.md"};function r(d,i,l,h,o,p){return s(),a("div",null,[...i[0]||(i[0]=[t(`<h1 id="server" tabindex="-1">Server <a class="header-anchor" href="#server" aria-label="Permalink to “Server”">​</a></h1><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to “Table of Contents”">​</a></h2><ul><li><a href="#overview">Overview</a></li><li><a href="#app-mode">App Mode</a></li><li><a href="#proxied-mode-and-trusted-proxies">Proxied Mode and Trusted Proxies</a></li><li><a href="#server-runtime-mode">Server Runtime Mode</a></li><li><a href="#running-in-single-process">Running in Single Process</a></li><li><a href="#running-in-cluster-mode">Running in Cluster Mode</a></li><li><a href="#protocol-and-tls-detection">Protocol and TLS Detection</a></li><li><a href="#configuration-reference">Configuration Reference</a></li><li><a href="#notes-and-current-behaviors">Notes and Current Behaviors</a></li></ul><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h2><p>Phenix runtime behavior is controlled by two independent configuration dimensions:</p><ul><li><strong>App Mode</strong> (<code>direct</code> or <code>proxied</code>): controls how client connection metadata is resolved.</li><li><strong>Server runtime mode</strong> (<code>single</code> or <code>cluster</code>): controls process model and worker execution.</li></ul><p>These are configured in <code>config/app.php</code>:</p><div class="language-php"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;app_mode&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> env</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;APP_MODE&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">static</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> fn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ()</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> =&gt; </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;direct&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;trusted_proxies&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> env</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;APP_TRUSTED_PROXIES&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">static</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> fn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ()</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> array</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> =&gt; []),</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;server_mode&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> env</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;APP_SERVER_MODE&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">static</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> fn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ()</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> =&gt; </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;single&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span></code></pre></div><p>For CORS configuration, see <a href="./middlewares.html#cors-handlecors">CORS (<code>HandleCors</code>)</a> in the Middlewares guide.</p><h2 id="app-mode" tabindex="-1">App Mode <a class="header-anchor" href="#app-mode" aria-label="Permalink to “App Mode”">​</a></h2><p><code>app.app_mode</code> supports:</p><ul><li><code>direct</code> (<code>AppMode::DIRECT</code>): server is exposed directly to clients.</li><li><code>proxied</code> (<code>AppMode::PROXIED</code>): server is behind a reverse proxy/load balancer and trusts forwarding headers from configured proxies.</li></ul><p>Use <code>direct</code> when the Phenix process receives traffic directly. Use <code>proxied</code> when requests come through Nginx, HAProxy, ALB, or similar infrastructure.</p><h2 id="proxied-mode-and-trusted-proxies" tabindex="-1">Proxied Mode and Trusted Proxies <a class="header-anchor" href="#proxied-mode-and-trusted-proxies" aria-label="Permalink to “Proxied Mode and Trusted Proxies”">​</a></h2><p>When <code>app_mode</code> is <code>proxied</code>, <code>app.trusted_proxies</code> must be a non-empty array of trusted IPs or CIDRs.</p><p>If <code>trusted_proxies</code> is empty, server boot fails with a <code>RuntimeError</code>:</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Trusted proxies must be an array of IP addresses or CIDRs.</span></span></code></pre></div><p>Example configuration:</p><div class="language-php"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;app_mode&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;proxied&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;trusted_proxies&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;127.0.0.1/32&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;10.0.0.0/8&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span></code></pre></div><p>Security guidance: trust only known proxy IP ranges. Do not use broad or unknown ranges.</p><h2 id="server-runtime-mode" tabindex="-1">Server Runtime Mode <a class="header-anchor" href="#server-runtime-mode" aria-label="Permalink to “Server Runtime Mode”">​</a></h2><p><code>app.server_mode</code> supports:</p><ul><li><code>single</code> (<code>ServerMode::SINGLE</code>): one server process.</li><li><code>cluster</code> (<code>ServerMode::CLUSTER</code>): multiple workers via <code>amphp/cluster</code>.</li></ul><p>In cluster mode, the app uses cluster termination flow (<code>Cluster::awaitTermination()</code>).<br> In non-cluster mode, the app uses signal trapping (<code>SIGHUP</code>, <code>SIGINT</code>, <code>SIGQUIT</code>, <code>SIGTERM</code>) for graceful stop.</p><h2 id="running-in-single-process" tabindex="-1">Running in Single Process <a class="header-anchor" href="#running-in-single-process" aria-label="Permalink to “Running in Single Process”">​</a></h2><p>Default behavior:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> public/index.php</span></span></code></pre></div><h2 id="running-in-cluster-mode" tabindex="-1">Running in Cluster Mode <a class="header-anchor" href="#running-in-cluster-mode" aria-label="Permalink to “Running in Cluster Mode”">​</a></h2><p>To run with worker processes:</p><div class="language-ini"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">APP_SERVER_MODE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=cluster</span></span></code></pre></div><p>Then, execute cluster:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vendor/bin/cluster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> public/index.php</span></span></code></pre></div><p>Optional worker count:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vendor/bin/cluster</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> public/index.php</span></span></code></pre></div><p>You can inspect additional options with:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vendor/bin/cluster</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div><h2 id="protocol-and-tls-detection" tabindex="-1">Protocol and TLS Detection <a class="header-anchor" href="#protocol-and-tls-detection" aria-label="Permalink to “Protocol and TLS Detection”">​</a></h2><p>Protocol is detected at runtime using <code>app.url</code> and <code>app.cert_path</code>:</p><ul><li><code>Protocol::HTTPS</code> is used only when <code>app.url</code> starts with <code>https://</code> and <code>app.cert_path</code> is not <code>null</code>.</li><li>Otherwise, Phenix runs as <code>Protocol::HTTP</code>.</li></ul><p>TLS example:</p><div class="language-php"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;url&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://127.0.0.1&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;port&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1337</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;cert_path&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> base_path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;certs/server.pem&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span></code></pre></div><h2 id="configuration-reference" tabindex="-1">Configuration Reference <a class="header-anchor" href="#configuration-reference" aria-label="Permalink to “Configuration Reference”">​</a></h2><table tabindex="0"><thead><tr><th>Key</th><th>Type</th><th>Values / Meaning</th></tr></thead><tbody><tr><td><code>app.app_mode</code></td><td><code>string</code></td><td><code>direct</code> | <code>proxied</code></td></tr><tr><td><code>app.trusted_proxies</code></td><td><code>array&lt;string&gt;</code></td><td>Trusted proxy IPs/CIDRs (required when <code>proxied</code>)</td></tr><tr><td><code>app.server_mode</code></td><td><code>string</code></td><td><code>single</code> | <code>cluster</code></td></tr><tr><td><code>app.url</code></td><td><code>string</code></td><td>Base application URL</td></tr><tr><td><code>app.port</code></td><td><code>int</code></td><td>Port used by exposed socket</td></tr><tr><td><code>app.cert_path</code></td><td><code>string | null</code></td><td>TLS certificate path used for HTTPS</td></tr></tbody></table><h2 id="notes-and-current-behaviors" tabindex="-1">Notes and Current Behaviors <a class="header-anchor" href="#notes-and-current-behaviors" aria-label="Permalink to “Notes and Current Behaviors”">​</a></h2><ul><li>Invalid <code>app_mode</code> values fall back to <code>direct</code>.</li><li>Invalid <code>server_mode</code> values fall back to <code>single</code>.</li><li>Trusted proxies validation is applied in both single and cluster servers when <code>app_mode=proxied</code>.</li><li>Cluster mode and app mode are independent. You can run <code>cluster + direct</code> or <code>cluster + proxied</code>.</li></ul>`,45)])])}const g=e(n,[["render",r]]);export{k as __pageData,g as default};
